    public async Task Invoke(HttpContext context)
    {
        if (!Config.BaseConfig.UsingAuth) //不使用鉴权
        {
            context.Items["authWebStatus"] = "OK";
            context.Items["isAdmin"] = "Yes";
            context.Items["tenant"] = "Default";

            string cacheKey = "Auth_NoAuth";
            // var cache = redis.Get(cacheKey);
            var user = redis.GetFromCache<AuthInfo>(cacheKey);

            if (user == null)
            {
                user = new AuthInfo();
                user.UserAccount = "1000";
                user.UserName = "测试";
                user.IsAdmin = true;
                user.Tenant = "Default";
                redis.Insert(cacheKey, user.ToJsonString(), DateTime.Now.AddDays(1));
            }

            await _next(context);
        }
        else
        {
            string tokenString = Config.BaseConfig.TokenString;
            string tp_token = context.Request.Cookies[tokenString];
            if (string.IsNullOrEmpty(tp_token))
            {
                tp_token = context.Request.Headers[tokenString];
            }

            if (string.IsNullOrEmpty(tp_token))
            {
                context.Items["authWebStatus"] = "No Token";
                FunConsole.ConsoleLog("无Token", context.Request.Path);
            }
            else
            {
                var userinfo = UserInfo.GetFromToken(tp_token);

                var user = redis.GetFromCache<AuthInfo>("Auth_" + userinfo.Account);

                if (user != null)
                {
                    FunConsole.ConsoleLog("缓存中取User", user.ToJsonString());
                    context.Items["authWebStatus"] = "OK";

                    //此处管理员帐号在配置中，是举例，各个系统可酌情考虑
                    if (Config.BaseConfig.AdminList.Contains(userinfo.Account))
                    {
                        context.Items["isAdmin"] = "Yes";
                    }

                    context.Items["tenant"] = user.Tenant;

                    FunConsole.ConsoleLog("缓存中User不为空");

                }
                else
                {
                    FunConsole.ConsoleLog("缓存中取User为空");

                    if (!Config.BaseConfig.UseLoginLoginAuth) //不使用本地鉴权
                    {
                        string totalURL = context.Request.Scheme + "://" +
                                          context.Request.Host +
                                          context.Request.Path +
                                          context.Request.QueryString ?? "";

                        string res = FunHttp_TotalLogin.CheckToken(tp_token, totalURL);
                        // var res2 = (JObject)JsonConvert.DeserializeObject(res1);
                        // string res = res2["status"].ToString();

                        FunConsole.ConsoleLog("鉴权结果", res);

                        if (res == "OK")
                        {
                            context.Items["authWebStatus"] = "OK";

                            bool isAdmin = false;

                            //此处管理员帐号在配置中，是举例，各个系统可酌情考虑
                            if (Config.BaseConfig.AdminList.Contains(userinfo.Account))
                            {
                                context.Items["isAdmin"] = "Yes";
                                isAdmin = true;
                            }

                            //到sys_user中查询该用户的租户
                            var sysUser = sysUserBusiness.GetAll()
                                .Find(x => x.Account == userinfo.Account);

                            if (sysUser != null)
                            {
                                context.Items["tenant"] = sysUser.Tenant;
                            }
                            else
                            {
                                context.Items["tenant"] = "Default";
                                //异步向sys_user中插入一条
                                InsertToSys_User(userinfo, "");
                            }

                            user = new AuthInfo();
                            user.UserAccount = userinfo.Account;
                            user.UserName = userinfo.UserName;
                            user.IsAdmin = isAdmin;
                            user.Tenant = sysUser?.Tenant;

                            redis.Insert("Auth_" + userinfo.Account,
                                user.ToJsonString(), userinfo.exp);

                        }
                        else
                        {
                            context.Items["authWebStatus"] = res;
                        }
                    }
                    else  //使用本地鉴权
                    {
                        var (status, msg, checkedUser) = tokenBusiness.TokenTest(tp_token);

                        Logger.Info("本地鉴权结果", msg + " " + JsonConvert.SerializeObject(checkedUser));

                        if (status)
                        {
                            context.Items["authWebStatus"] = "OK";

                            bool isAdmin = false;

                            //此处管理员帐号在配置中，是举例，各个系统可酌情考虑
                            if (Config.BaseConfig.AdminList.Contains(userinfo.Account))
                            {
                                isAdmin = true;
                                context.Items["isAdmin"] = "Yes";
                            }

                            //var authuser = new AuthInfo
                            //{
                            //    UserAccount = userinfo.Account,
                            //    UserName = userinfo.UserName,
                            //    IsAdmin = isAdmin,
                            //    Tenant = userinfo.Tenant,
                            //};

                            //redis.Insert("Auth_" + userinfo.Account,
                            //    user.ToJsonString(), userinfo.exp);
                        }
                        else
                        {
                            context.Items["authWebStatus"] = msg;
                        }


                    }



                }

            }
            await _next(context);
        }
    }

